import { Component, Inject, OnInit } from '@angular/core';
import { UntypedFormBuilder, UntypedFormGroup } from '@angular/forms';
import { MAT_DIALOG_DATA, MatDialogRef } from '@angular/material/dialog';
import { Activitymaster } from '../interfaces/activitymaster.model';
import { ActivitymasterService } from '../activitymaster.service';

@Component({
  selector: 'ux-activitymaster-create-update',
  templateUrl: './activitymaster-create-update.component.html',
  styleUrls: ['./activitymaster-create-update.component.scss']
})
export class ActivitymasterCreateUpdateComponent implements OnInit {

  form: UntypedFormGroup;
  mode: 'create' | 'update' = 'create';

  constructor(@Inject(MAT_DIALOG_DATA) public defaults: any,
              private dialogRef: MatDialogRef<ActivitymasterCreateUpdateComponent>,
              private fb: UntypedFormBuilder,
              private activitymasterService: ActivitymasterService
              ) {
  }

  ngOnInit() {
    if (this.defaults) {
      this.mode = 'update';
    } else {
      this.defaults = {} as Activitymaster;
    }

    this.form = this.fb.group({
      activity_id: this.defaults._id || '',
      activity_name: this.defaults.activity_name,
      activity_description: [this.defaults.activity_description || ''],
      status: this.defaults.status || '1'
    });
  }

  save() {
    if (this.mode === 'create') {
      this.createActivitymaster();
    } else if (this.mode === 'update') {
      this.updateActivitymaster();
    }
  }

  createActivitymaster() {
    const activitymaster = this.form.value;
    this.dialogRef.close(activitymaster);
  }

  updateActivitymaster() {
    const activitymaster = this.form.value;
    activitymaster._id = this.defaults._id;

    this.dialogRef.close(activitymaster);
  }

  isCreateMode() {
    return this.mode === 'create';
  }

  isUpdateMode() {
    return this.mode === 'update';
  }
}
